  "inlineSchema": "// Prisma schema for Homeopathic Pharmacy & Remedies Management System\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Auth Models (Better Auth) ────────────────────────────────────────────────\n\nmodel User {\n  id            String   @id\n  name          String\n  email         String\n  emailVerified Boolean  @default(false)\n  image         String?\n  role          String   @default(\"USER\") // USER | ADMIN\n  loyaltyPoints Int      @default(0)\n  phone         String?\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @default(now()) @updatedAt\n\n  sessions            Session[]\n  accounts            Account[]\n  cartItems           CartItem[]\n  orders              Order[]\n  reviews             Review[]\n  loyaltyTransactions LoyaltyTransaction[]\n\n  @@unique([email])\n  @@map(\"user\")\n}\n\nmodel Session {\n  id        String   @id\n  expiresAt DateTime\n  token     String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  ipAddress String?\n  userAgent String?\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([token])\n  @@map(\"session\")\n}\n\nmodel Account {\n  id                    String    @id\n  accountId             String\n  providerId            String\n  userId                String\n  user                  User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  accessToken           String?\n  refreshToken          String?\n  idToken               String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String?\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  @@map(\"account\")\n}\n\nmodel Verification {\n  id         String   @id\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @default(now()) @updatedAt\n\n  @@map(\"verification\")\n}\n\n// ─── Pharmacy Models ──────────────────────────────────────────────────────────\n\nmodel Category {\n  id          String    @id @default(cuid())\n  name        String\n  slug        String    @unique\n  description String?\n  image       String?\n  createdAt   DateTime  @default(now())\n  products    Product[]\n}\n\nmodel Product {\n  id          String   @id @default(cuid())\n  name        String\n  slug        String   @unique\n  categoryId  String\n  category    Category @relation(fields: [categoryId], references: [id])\n  potency     String? // e.g. \"30C\", \"200C\", \"Q\"\n  indications String? // What it treats\n  dosage      String?\n  ingredients String?\n  directions  String?\n  price       Float\n  stock       Int      @default(0)\n  image       String?\n  isFeatured  Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  cartItems  CartItem[]\n  orderItems OrderItem[]\n  reviews    Review[]\n\n  @@index([slug])\n  @@index([categoryId])\n}\n\nmodel CartItem {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  productId String\n  product   Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  quantity  Int      @default(1)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, productId])\n}\n\nmodel Order {\n  id            String   @id @default(cuid())\n  userId        String\n  user          User     @relation(fields: [userId], references: [id])\n  total         Float\n  paymentMethod String // CARD | BKASH | NAGAD | COD\n  status        String   @default(\"PLACED\") // PLACED|CONFIRMED|PROCESSING|SHIPPED|OUT_FOR_DELIVERY|DELIVERED|CANCELLED\n  address       String\n  phone         String\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  items          OrderItem[]\n  trackingEvents OrderTracking[]\n}\n\nmodel OrderItem {\n  id        String  @id @default(cuid())\n  orderId   String\n  order     Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId String\n  product   Product @relation(fields: [productId], references: [id])\n  quantity  Int\n  price     Float // price at time of order\n\n  @@index([orderId])\n}\n\nmodel OrderTracking {\n  id        String   @id @default(cuid())\n  orderId   String\n  order     Order    @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  status    String // PLACED|CONFIRMED|PROCESSING|SHIPPED|OUT_FOR_DELIVERY|DELIVERED\n  note      String?\n  createdAt DateTime @default(now())\n\n  @@index([orderId])\n}\n\nmodel Review {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  productId String\n  product   Product  @relation(fields: [productId], references: [id], onDelete: Cascade)\n  rating    Int // 1-5\n  comment   String?\n  createdAt DateTime @default(now())\n\n  @@unique([userId, productId])\n}\n\nmodel BlogPost {\n  id          String   @id @default(cuid())\n  title       String\n  slug        String   @unique\n  excerpt     String\n  content     String\n  image       String?\n  category    String   @default(\"General\") // Remedies | Seasonal | Health Awareness\n  publishedAt DateTime @default(now())\n  createdAt   DateTime @default(now())\n}\n\nmodel LoyaltyTransaction {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  points    Int // positive = earned, negative = redeemed\n  reason    String\n  createdAt DateTime @default(now())\n}\n",
